import React, { useState, useEffect } from 'react';
import useGetDate from '../Hooks/useGetDate';
import useGetSingleAPOD from '../Hooks/useGetSingleAPOD';
import { BASE_API_URL } from '../utils/constants';

const Single = () => {

  const [apod, setApod] = useState(null);
  const [err, setErr] = useState(null);
  const [todaysDate, setTodaysDate] = useState(null);
  const [userDate, setUserDate] = useState(null);
  const [loading, setLoading] = useState('');

  

  useEffect(() => {
    const singleDay = localStorage.getItem('singleDay');

    if (singleDay) {
      // setting the max date
      let date = new Date();
      const today = useGetDate(date);
      setTodaysDate(today);
      // retrieving the previously set single day
      const obj = JSON.parse(singleDay);
      setUserDate(obj.date);
      setApod(obj);
    } else {
      let date = new Date();
      const today = useGetDate(date);
      setTodaysDate(today);
      setUserDate(today);
    }

  }, []);

  // useEffect(() => {

  //   if (!data) {
  //     return 
  //   } else if (data.error) {
  //     setErr(data);
  //   } else {
  //     setApod(data);
  //   }

  // }, [data]);

  const handleDate = (e) => {
    e.preventDefault();
    console.log(userDate);
    setLoading('Loading...');
    getPhoto(userDate);
  }

  const getPhoto = (date) => {
    console.log('date: ', date);
    setLoading('Loading...');
    fetch(`${BASE_API_URL}/api/single-img?date=${date}`, {
      method: 'GET'
    })
    .then(response => response.json())
    .then(data => {
      // if a status code other than 200 is sent back
      if (data.error) {
        setLoading('');
        setApod(null);
        setErr(data);
      } else {
        setLoading('');
        setApod(data);
        setErr(null);
        console.log(data);
        localStorage.setItem('singleDay', JSON.stringify(data));
      }
    })
    .catch(error => {
      console.log(error);
    });
  };

  return (
    <div className='single-div'>
      <header className='single-header'>
        <h1>Single APOD</h1>
        <p>Select a single date or scroll with the buttons</p>
      </header>
      <div className="single-form-wrap">
          <form>
            <div className="start-container">
              <label htmlFor="start">Your date 
              (earliest date: 06-16-1995): </label>
              {/* TODO add onchange to set date state */}
              <input type="date" id="start" name="apod-start" min="1995-06-16" max={todaysDate} value={userDate ? userDate : todaysDate} onChange={(e) => setUserDate(e.target.value)}/>
            </div>   

            <button className="update-btn" onClick={handleDate}>Update pictures</button>
          </form>
        </div>
      <div className="ui-text">{err 
        ? <div className="error-text">{err}</div> 
        : <div className="loading-text">{loading}</div>
      }
      </div>

      {apod && <NasaObj apod={apod} /> }
    </div>
  )
}

export default Single
